28	// Policy filter is a mechanism for restricting  tracing policies on a subset
29	// of pods running in the node. Policies are identified by their policyID and
30	// the pod processes are identified the cgroup ids of their containers.
31	//
32	// The pods that match a given policy are selected based on:
33	//   (1) Namespaces
34	//   (2) Label filters
35	//   (3) Container field filters
36	//
37	// This package maintains the 'policy_filter_maps' bpf map. Bpf checks this map
38	// to decide whether a policy is applied or not. The map is a hash-of-hashes:
39	//
40	//   policy_id -> [ cgroup_id -> u8 ]
41	//
42	// If entry policy_id -> cgroup_id exists, then policy is to be applied. (u8 value is ignored for
43	// now.)
44	//
45	// This package provides functions that can be used to update the bpf map. The map
46	// needs to be updated in the following conditions:
47	//
48	//  (A) Policy changes: when a new policy is added (or deleted), we need to add cgroup ids of
49	//  matching containers inside pods. See {Add,Del}Policy.
50	//
51	//  (B) Pod containers changes: when new containers are added (or deleted): we need to add the cgroup
52	//  ids of matching policies. See AddPodContainer, DelPodContainer, DelPod, UpdatePod.
53	//
54	//  (C) Pod labels change: need to rescan policies because the result of pod label filters might have
55	//  changed. See UpdatePod.
56	//
57	// Todo:
58	//  - use a goroutine and a queue
59	//  (https://github.com/kubernetes/client-go/blob/master/examples/workqueue/main.go) instead locks
60	//  for serialization
61	
62	func init() {
63		podhooks.RegisterCallbacksAtInit(podhooks.Callbacks{
64			PodCallbacks: func(podInformer cache.SharedIndexInformer) {
65				// register pod handlers for policyfilters
66				if pfState, err := GetState(); err == nil {
67					logger.GetLogger().Info("registering policyfilter pod handlers")
68					pfState.RegisterPodHandlers(podInformer)
69				}
70			},
71		})
72	}
