74	const (
75		// polMapSize is the number of entries for the (inner) policy map. It
76		// should be large enough to accommodate the number of containers
77		// running in a system.
78		polMapSize = 32768
79	
80		// same as POLICY_FILTER_MAX_POLICIES in policy_filter.h
81		polMaxPolicies = 128
