84	type PolicyID uint32
85	type PodID uuid.UUID
86	type CgroupID uint64
87	type StateID uint64
88	
89	const (
90		// we reserve 0 as a special value to indicate no filtering
91		NoFilterPolicyID         = 0
92		NoFilterID               = PolicyID(NoFilterPolicyID)
93		FirstValidFilterPolicyID = NoFilterPolicyID + 1
94	)
95	
96	func (i PodID) String() string {
97		var x = uuid.UUID(i)
98		return x.String()
99	}
100	
101	type containerInfo struct {
102		id   string   // container id
103		cgID CgroupID // cgroup id
104		name string   // container name
105		repo string   // container repo
106	}
107	
108	// podInfo contains the necessary information for each pod
109	type podInfo struct {
110		id         PodID
111		namespace  string
112		labels     labels.Labels
113		workload   string
114		kind       string
115		containers []containerInfo
116	
117		// cache of matched policies
118		matchedPolicies []PolicyID
119	}
