121	// delete containers from a pod based on their id, and return them
122	// NB: in most cases there will be a single container, but we do not reject users adding a container
123	// with the same id and different cgroup, so we return a list to cover all cases.
124	func (pod *podInfo) delContainers(id string) []containerInfo {
125		var ret []containerInfo
126		for i := 0; i < len(pod.containers); i++ {
127			c := pod.containers[i]
128			if c.id == id {
129				ret = append(ret, c)
130				pod.containers = append(pod.containers[:i], pod.containers[i+1:]...)
131				i--
132			}
133		}
134		return ret
135	}
136	
137	func (pod *podInfo) delCachedPolicy(polID PolicyID) {
138		for i := 0; i < len(pod.matchedPolicies); i++ {
139			if pod.matchedPolicies[i] == polID {
140				pod.matchedPolicies = append(pod.matchedPolicies[:i], pod.matchedPolicies[i+1:]...)
141			}
142		}
143	}
144	
145	func (pod *podInfo) addCachedPolicy(polID PolicyID) {
146		for i := range len(pod.matchedPolicies) {
147			if pod.matchedPolicies[i] == polID {
148				return
149			}
150		}
151		pod.matchedPolicies = append(pod.matchedPolicies, polID)
152	}
153	
154	func (pod *podInfo) hasPolicy(polID PolicyID) bool {
155		for i := range len(pod.matchedPolicies) {
156			if pod.matchedPolicies[i] == polID {
157				return true
158			}
159		}
160		return false
161	}
162	
163	// containerExists checks returns true if a container exists in the pod
164	func (m *state) containerExists(pod *podInfo, containerID string, cgIDp *CgroupID) bool {
165		for i := range pod.containers {
166			container := &pod.containers[i]
167			if container.id != containerID {
168				continue
169			}
170	
171			// we found a matching container id, if no cgroup id is given, return
172			if cgIDp == nil {
173				return true
174			}
175	
176			// otherwise, also check that the cgroup id matches
177			if container.id == containerID && container.cgID == *cgIDp {
178				// container was already handled, return
179				return true
180			}
181	
182			// issue  a warning and continue
183			// NB: if this happens, we might end up with multiple cgroup
184			// ids for the same container. Since we have no way of knowing
185			// which one is the correct, we keep both.
186			m.log.Warn("AddPodContainer: conflicting cgroup ids",
187				"pod-id", pod.id,
188				"container-id", containerID,
189				"old-cgroup-id", container.cgID,
190				"new-cgroup-id", *cgIDp)
191		}
192	
193		return false
194	}
195	
196	type policy struct {
197		id PolicyID
198	
199		// if namespace is "", policy applies to all namespaces
200		namespace string
201	
202		containerSelector labels.Selector
203	
204		podSelector labels.Selector
205	
206		// polMap is the (inner) policy map for this policy
207		polMap polMap
208	}
209	
210	func (pol *policy) podMatches(podNs string, podLabels labels.Labels) bool {
211		if pol.namespace != "" && podNs != pol.namespace {
212			return false
213		}
214		var podLabels1 labels.Labels
215		if podLabels != nil {
216			podLabels1 = podLabels
217		} else {
218			podLabels1 = make(labels.Labels)
219		}
220	
221		if _, ok := podLabels1[labels.K8sPodNamespace]; !ok {
222			podLabels1[labels.K8sPodNamespace] = podNs
223		}
224	
225		return pol.podSelector.Match(podLabels1)
226	}
227	
228	func (pol *policy) podInfoMatches(pod *podInfo) bool {
229		return pol.podMatches(pod.namespace, pod.labels)
230	}
231	
232	func (pol *policy) containerMatches(container *containerInfo) bool {
233		containerFilterFields := labels.Labels{
234			"name": container.name,
235			"repo": container.repo,
236		}
237		return pol.containerSelector.Match(containerFilterFields)
238	}
239	
240	// get a slice of container cgroupIDs that match the policy
241	func (pol *policy) matchingContainersCgroupIDs(containers []containerInfo) []CgroupID {
242		var cgroupIDs []CgroupID
243		for i := range containers {
244			container := containers[i]
245			if pol.containerMatches(&container) {
246				cgroupIDs = append(cgroupIDs, container.cgID)
247			}
248		}
249		return cgroupIDs
250	}
