252	// State holds the necessary state for policyfilter
253	type state struct {
254		log *slog.Logger
255		*logger.DebugLogger
256	
257		// mutex serializes access to the internal structures, as well as operations.
258		mu       sync.Mutex
259		policies []policy
260		pods     []podInfo
261	
262		// polify filters (outer) map handle
263		pfMap PfMap
264	
265		// global policy map handle
266		nsMap *NamespaceMap
267	
268		cgidFinder cgidFinder
269	}
