271	// New creates a new State of the policy filter code. Callers should call Close() to release
272	// allocated resources (namely the bpf map).
273	//
274	//revive:disable:unexported-return
275	func New(enableCgroupMap bool) (*state, error) {
276		log := logger.GetLogger().With("subsystem", "policy-filter")
277		return newState(
278			log,
279			&cgfsFinder{fsscan.New(), log},
280			enableCgroupMap,
281		)
282	}
