284	func newState(
285		log *slog.Logger,
286		cgidFinder cgidFinder,
287		enableCgroupMap bool,
288	) (*state, error) {
289		var err error
290		ret := &state{
291			log:         log,
292			cgidFinder:  cgidFinder,
293			DebugLogger: logger.NewDebugLogger(log, option.Config.EnablePolicyFilterDebug),
294		}
295	
296		ret.pfMap, err = newPfMap(enableCgroupMap)
297		if err != nil {
298			return nil, err
299		}
300	
301		ret.nsMap, err = newNamespaceMap()
302		if err != nil {
303			return nil, err
304		}
305	
306		return ret, nil
307	}
