309	//revive:enable:unexported-return
310	
311	func (m *state) updatePodHandler(pod *v1.Pod) error {
312		containerIDs := podhelpers.PodContainersIDs(pod)
313		containerInfo := podhelpers.PodContainersInfo(pod)
314		podID, err := uuid.Parse(string(pod.UID))
315		if err != nil {
316			m.log.Warn("policyfilter, pod handler: failed to parse pod id", logfields.Error, err, "pod-id", pod.UID)
317			return err
318		}
319	
320		namespace := pod.Namespace
321		workloadMeta, kindMeta := podhelpers.GetWorkloadMetaFromPod(pod)
322		workload := workloadMeta.Name
323		kind := kindMeta.Kind
324	
325		err = m.UpdatePod(PodID(podID), namespace, workload, kind, pod.Labels, containerIDs, containerInfo)
326		if err != nil {
327			m.log.Warn("policyfilter, UpdatePod failed",
328				logfields.Error, err,
329				"pod-id", podID,
330				"container-ids", containerIDs,
331				"namespace", namespace,
332				"workload", workload,
333				"kind", kind)
334			return err
335		}
336	
337		return nil
338	}
339	
340	func (m *state) getPodEventHandlers() cache.ResourceEventHandlerFuncs {
341		return cache.ResourceEventHandlerFuncs{
342			AddFunc: func(obj interface{}) {
343				pod, ok := obj.(*v1.Pod)
344				if !ok {
345					logger.GetLogger().Warn(fmt.Sprintf("policyfilter, add-pod handler: unexpected object type: %T", pod))
346					return
347				}
348				err := m.updatePodHandler(pod)
349				policyfiltermetrics.OpInc(policyfiltermetrics.PodHandlersSubsys, policyfiltermetrics.AddPodOperation, ErrorLabel(err))
350			},
351			UpdateFunc: func(_, newObj interface{}) {
352				pod, ok := newObj.(*v1.Pod)
353				if !ok {
354					logger.GetLogger().Warn(fmt.Sprintf("policyfilter, update-pod handler: unexpected object type(s): new:%T", pod))
355					return
356				}
357				err := m.updatePodHandler(pod)
358				policyfiltermetrics.OpInc(policyfiltermetrics.PodHandlersSubsys, policyfiltermetrics.UpdatePodOperation, ErrorLabel(err))
359			},
360			DeleteFunc: func(obj interface{}) {
361				// Remove all containers for this pod
362				pod, ok := obj.(*v1.Pod)
363				if !ok {
364					logger.GetLogger().Warn(fmt.Sprintf("policyfilter, delete-pod handler: unexpected object type: %T", pod))
365					return
366				}
367				podID, err := uuid.Parse(string(pod.UID))
368				if err != nil {
369					logger.GetLogger().Warn("policyfilter, delete-pod: failed to parse id", "pod-id", pod.UID, logfields.Error, err)
370					return
371				}
372	
373				namespace := pod.Namespace
374				err = m.DelPod(PodID(podID))
375				if err != nil {
376					logger.GetLogger().Warn("policyfilter, delete-pod handler: DelPod failed",
377						logfields.Error, err,
378						"pod-id", podID,
379						"namespace", namespace)
380				}
381				policyfiltermetrics.OpInc(policyfiltermetrics.PodHandlersSubsys, policyfiltermetrics.DeletePodOperation, ErrorLabel(err))
382			},
383		}
384	}
385	
386	func (m *state) RegisterPodHandlers(podInformer cache.SharedIndexInformer) {
387		podInformer.AddEventHandler(m.getPodEventHandlers())
388	}
389	
390	// Close releases resources allocated by the Manager. Specifically, we close and unpin the policy filter map.
391	func (m *state) Close() error {
392		return m.pfMap.release()
393	}
394	
395	func (m *state) findPolicy(id PolicyID) *policy {
396		for i := range m.policies {
397			if m.policies[i].id == id {
398				return &m.policies[i]
399			}
400		}
401		return nil
402	}
403	
404	// delPolicy removes a policy and returns it, or returns nil if policy is not found
405	func (m *state) delPolicy(id PolicyID) *policy {
406		for i, pol := range m.policies {
407			if pol.id == id {
408				m.policies = append(m.policies[:i], m.policies[i+1:]...)
409				return &pol
410			}
411		}
412		return nil
413	}
414	
415	// find the pod with the given id
416	func (m *state) findPod(id PodID) *podInfo {
417		for i := range m.pods {
418			if m.pods[i].id == id {
419				return &m.pods[i]
420			}
421		}
422		return nil
423	}
424	
425	func (m *state) delPod(id PodID) *podInfo {
426		for i, pod := range m.pods {
427			if pod.id == id {
428				m.pods = append(m.pods[:i], m.pods[i+1:]...)
429				return &pod
430			}
431		}
432		return nil
433	}
434	
435	// AddPolicy adds a policy
436	func (m *state) AddPolicy(polID PolicyID, namespace string, podLabelSelector *slimv1.LabelSelector,
437		containerLabelSelector *slimv1.LabelSelector) error {
438		m.mu.Lock()
439		defer m.mu.Unlock()
440	
441		if p := m.findPolicy(polID); p != nil {
442			return fmt.Errorf("policy with id %d already exists: not adding new one", polID)
443		}
444	
445		podSelector, err := labels.SelectorFromLabelSelector(podLabelSelector)
446		if err != nil {
447			return err
448		}
449	
450		containerSelector, err := labels.SelectorFromLabelSelector(containerLabelSelector)
451		if err != nil {
452			return err
453		}
454	
455		policy := policy{
456			id:                polID,
457			namespace:         namespace,
458			podSelector:       podSelector,
459			containerSelector: containerSelector,
460		}
461	
462		cgroupIDs := make([]CgroupID, 0)
463		// scan pods to find the ones that match this policy to set initial state for policy
464		matchedPods := make([]*podInfo, 0, len(m.pods))
465		for i := range m.pods {
466			pod := &m.pods[i]
467			if !policy.podInfoMatches(pod) {
468				continue
469			}
470	
471			matchedContainerCgroupIDs := policy.matchingContainersCgroupIDs(pod.containers)
472			cgroupIDs = append(cgroupIDs, matchedContainerCgroupIDs...)
473	
474			matchedPods = append(matchedPods, pod)
475			pod.addCachedPolicy(policy.id)
476		}
477	
478		// update state for policy
479		policy.polMap, err = m.pfMap.newPolicyMap(polID, cgroupIDs)
480		if err != nil {
481			for _, pod := range matchedPods {
482				pod.delCachedPolicy(policy.id)
483			}
484			return fmt.Errorf("adding policy data to map failed: %w", err)
485		}
486	
487		m.policies = append(m.policies, policy)
488	
489		return nil
490	}
491	
492	// DelPolicy will destroy all information for the provided policy
493	func (m *state) DelPolicy(polID PolicyID) error {
494	
495		if polID == NoFilterPolicyID {
496			return nil
497		}
498	
499		m.mu.Lock()
500		defer m.mu.Unlock()
501		policy := m.delPolicy(polID)
502		if policy != nil {
503			policy.polMap.Inner.Close()
504		} else {
505			m.log.Warn("DelPolicy: policy internal map not found", "policy-id", polID)
506		}
507	
508		if err := m.pfMap.policyMap.Delete(polID); err != nil {
509			m.log.Warn("DelPolicy: failed to remove policy from external map", "policy-id", polID)
510		}
511	
512		// update cgroup map
513		m.pfMap.deletePolicyIDInCgroupMap(polID)
514	
515		for i := range m.pods {
516			pod := &m.pods[i]
517			pod.delCachedPolicy(policy.id)
518		}
519	
520		return nil
521	}
522	
523	func cgIDPointerStr(p *CgroupID) string {
524		if p == nil {
525			return "(unknown)"
526		}
527		return fmt.Sprintf("%d", *p)
528	}
529	
530	// addCgroupIDs add cgroups ids to the policy map
531	// todo: use batch operations when supported
532	func (m *state) addCgroupIDs(cinfo []containerInfo, pod *podInfo) error {
533		nsmap := m.nsMap
534	
535		for _, c := range cinfo {
536			key := NSID{
537				Namespace: pod.namespace,
538				Workload:  pod.workload,
539				Kind:      pod.kind,
540			}
541			id, ok := nsmap.nsNameMap.Get(key)
542			if ok {
543				if err := nsmap.cgroupIdMap.Update(&c.cgID, id, ebpf.UpdateAny); err != nil {
544					logger.GetLogger().Warn("Unable to assign cgroup to existing namespace", logfields.Error, err)
545				}
546				continue
547			}
548			logger.GetLogger().Debug("update cgroupid map", "cgrp", c, "pod", pod, "id", nsmap.id)
549	
550			// If this is a new namespace we create a new map entry and bind it to a stable id.
551			if err := nsmap.cgroupIdMap.Update(&c.cgID, nsmap.id, ebpf.UpdateAny); err != nil {
552				logger.GetLogger().Warn("Unable to insert cgroup id map",
553					logfields.Error, err,
554					"cgid", c.cgID,
555					"id", nsmap.id,
556					"ns", c.name)
557				continue
558			}
559			if ok := nsmap.nsIdMap.Add(nsmap.id, key); ok {
560				logger.GetLogger().Info("Id to namespace map caused eviction",
561					"cgid", c.cgID,
562					"id", nsmap.id,
563					"ns", c.name)
564			}
565			if ok := nsmap.nsNameMap.Add(key, nsmap.id); ok {
566				logger.GetLogger().Info("Namespace to Id map caused eviction",
567					"cgid", c.cgID,
568					"id", nsmap.id,
569					"ns", c.name)
570			}
571			nsmap.id++
572		}
573	
574		return nil
575	}
576	
577	// addPodContainers adds a list of containers (ids) to a pod.
578	// It will update the state for all containers that do not exist.
579	// It takes an optional argument of a list of cgroup ids (one per container). If this list is empty,
580	// the function will try to figure out the cgroup id on its own.
581	// Finally, it will scan over all the matching policies for the pod and update the policy maps.
582	func (m *state) addPodContainers(pod *podInfo, containerIDs []string,
583		cgroupIDs []CgroupID, containerData []podhelpers.ContainerInfo) {
584		// Find the containers that do not exist in our state, and for those find the cgroup id if
585		// one does not exist.
586		cinfo := make([]containerInfo, 0, len(containerIDs))
587		for i, contID := range containerIDs {
588			var cgIDptr *CgroupID
589			if len(cgroupIDs) > i {
590				cgIDptr = &cgroupIDs[i]
591			}
592			containerData := containerData[i]
593	
594			if m.containerExists(pod, contID, cgIDptr) {
595				m.DebugLogWithCallers(4).Info("addPodContainers: container exists, skipping",
596					"pod-id", pod.id,
597					"namespace", pod.namespace,
598					"container-id", contID,
599					"cgroup-id", cgIDPointerStr(cgIDptr))
600				continue
601			}
602	
603			if cgIDptr == nil {
604				cgid, err := m.cgidFinder.findCgroupID(pod.id, contID)
605				if err != nil {
606					// error: skip this container id
607					m.log.Warn("failed to find cgroup id. Skipping container.",
608						logfields.Error, err,
609						"pod-id", pod.id,
610						"container-id", contID)
611					continue
612				}
613				cgIDptr = &cgid
614			}
615	
616			cinfo = append(cinfo, containerInfo{contID, *cgIDptr, containerData.Name, containerData.Repo})
617		}
618	
619		if len(cinfo) == 0 {
620			m.DebugLogWithCallers(4).Info("addPodContainers: nothing to do, returning",
621				"pod-id", pod.id,
622				"namespace", pod.namespace,
623				"container-ids", containerIDs)
624			return
625		}
626	
627		// update containers
628		pod.containers = append(pod.containers, cinfo...)
629		m.DebugLogWithCallers(4).Info("addPodContainers: container(s) added",
630			"pod-id", pod.id,
631			"namespace", pod.namespace,
632			"containers-info", cinfo)
633	
634		m.addCgroupIDs(cinfo, pod)
635	
636		// update matching policy maps
637		for _, policyID := range pod.matchedPolicies {
638			pol := m.findPolicy(policyID)
639			if pol == nil {
640				m.log.Warn("addPodContainers: unknown policy id found in pod. This should not happen, ignoring.",
641					"policy-id", policyID,
642					"pod-id", pod.id,
643					"cgroup-ids", cgroupIDs)
644				continue
645			}
646	
647			// cgroup IDs of containers that match the policy
648			matchingCgIDs := pol.matchingContainersCgroupIDs(pod.containers)
649	
650			if err := pol.polMap.addCgroupIDs(matchingCgIDs); err != nil {
651				m.log.Warn("failed to update policy map",
652					logfields.Error, err,
653					"policy-id", pol.id,
654					"pod-id", pod.id,
655					"cgroup-ids", matchingCgIDs)
656			} else {
657				if err := pol.polMap.addPolicyIDs(pol.id, matchingCgIDs); err != nil {
658					m.log.Warn("failed to update cgroup map",
659						logfields.Error, err,
660						"policy-id", pol.id,
661						"pod-id", pod.id,
662						"cgroup-ids", matchingCgIDs)
663				}
664			}
665		}
666	}
667	
668	func (m *state) addNewPod(podID PodID, namespace, workload, kind string, podLabels labels.Labels) *podInfo {
669		m.pods = append(m.pods, podInfo{
670			id:         podID,
671			namespace:  namespace,
672			workload:   workload,
673			kind:       kind,
674			labels:     podLabels,
675			containers: nil,
676		})
677		pod := &m.pods[len(m.pods)-1]
678		for i := range m.policies {
679			pol := &m.policies[i]
680			if pol.podInfoMatches(pod) {
681				pod.addCachedPolicy(pol.id)
682			}
683		}
684		return pod
685	}
686	
687	// AddPodContainer informs policyfilter about a new container in a pod.
688	// if the cgroup id of the container is known, cgID is not nil and it contains its value.
689	//
690	// The pod might or might not have been encountered before.
691	func (m *state) AddPodContainer(podID PodID, namespace, workload, kind string, podLabels labels.Labels,
692		containerID string, cgID CgroupID, containerInfo podhelpers.ContainerInfo) error {
693		m.mu.Lock()
694		defer m.mu.Unlock()
695	
696		pod := m.findPod(podID)
697		if pod == nil {
698			pod = m.addNewPod(podID, namespace, workload, kind, podLabels)
699			m.DebugLogWithCallers(4).Info("AddPodContainer: added pod",
700				"pod-id", podID,
701				"namespace", namespace,
702				"workload", workload,
703				"container-id", containerID,
704				"cgroup-id", cgID,
705				"container-info", containerInfo)
706		} else if pod.namespace != namespace {
707			// sanity check: old and new namespace should match
708			return &podNamespaceConflictError{podID: podID, oldNs: pod.namespace, newNs: namespace}
709		}
710	
711		m.addPodContainers(pod, []string{containerID}, []CgroupID{cgID}, []podhelpers.ContainerInfo{containerInfo})
712		return nil
713	}
714	
715	// delPodCgroupIDsFromPolicyMaps will delete cgorup entries for containers belonging to pod on all
716	// policy maps.
717	func (m *state) delPodCgroupIDsFromPolicyMaps(pod *podInfo, containers []containerInfo) {
718	
719		if len(containers) == 0 {
720			return
721		}
722	
723		// check what policies match the pod, and delete the cgroup ids
724		for _, policyID := range pod.matchedPolicies {
725			pol := m.findPolicy(policyID)
726			if pol == nil {
727				m.log.Warn("delPodCgroupIDsFromPolicyMaps: unknown policy id found in pod. This should not happen, ignoring.",
728					"policy-id", policyID,
729					"pod-id", pod.id)
730				continue
731			}
732	
733			// try to find containers in the pod matching this policy
734			// this way, we only remove containers that are actually present in the policy
735			cgroupIDs := pol.matchingContainersCgroupIDs(containers)
736			if err := pol.polMap.delCgroupIDs(pol.id, cgroupIDs); err != nil {
737				// NB: depending on the error, we might want to schedule some retries here
738				m.log.Warn("delPodCgroupIDsFromPolicyMaps: failed to delete cgroup ids from policy map",
739					logfields.Error, err,
740					"policy-id", pol.id,
741					"pod-id", pod.id,
742					"cgroup-ids", cgroupIDs)
743			}
744		}
745	}
746	
747	// DelPodContainer informs policyfilter that a container was deleted from a pod
748	func (m *state) DelPodContainer(podID PodID, containerID string) error {
749		m.mu.Lock()
750		defer m.mu.Unlock()
751	
752		pod := m.findPod(podID)
753		if pod == nil {
754			m.Debugf("DelPodContainer: pod-id %s not found", podID)
755			return nil
756		}
757	
758		containers := pod.delContainers(containerID)
759		if len(containers) != 1 {
760			m.Debugf("DelPodContainer: pod-id=%s container-id=%s had %d containers: %v", podID, containerID, len(containers), containers)
761		}
762		m.delPodCgroupIDsFromPolicyMaps(pod, containers)
763		return nil
764	}
765	
766	// DelPod informs policyfilter that a pod has been deleted
767	func (m *state) DelPod(podID PodID) error {
768		m.mu.Lock()
769		defer m.mu.Unlock()
770	
771		pod := m.delPod(podID)
772		if pod == nil {
773			m.Debug("DelPod: pod-id %s not found", podID)
774			return nil
775		}
776		m.delPodCgroupIDsFromPolicyMaps(pod, pod.containers)
777		return nil
778	}
779	
780	// policiesDiffRes is the result returned by policiesDiff
781	type policiesDiffRes struct {
782		// addedPolicies is a slice of the policies that were added
783		addedPolicies []*policy
784		// deletedPolicies is a slice of the policies that were removed
785		deletedPolicies []*policy
786		// newMatchedPolicies is a slice of the policy ids that now match the pod
787		newMatchedPolicies []PolicyID
788	}
789	
790	func (m *state) policiesDiff(pod *podInfo, newLabels labels.Labels) *policiesDiffRes {
791		addedPolicies := []*policy{}
792		deletedPolicies := []*policy{}
793	
794		newMatchedPolicies := []PolicyID{}
795		for i := range m.policies {
796			pol := &m.policies[i]
797			podHasPolicy := pod.hasPolicy(pol.id)
798			if pol.podMatches(pod.namespace, newLabels) {
799				newMatchedPolicies = append(newMatchedPolicies, pol.id)
800				if !podHasPolicy {
801					// policy matches, but pod does not have it in its matched policies.
802					addedPolicies = append(addedPolicies, pol)
803				}
804			} else if podHasPolicy {
805				// policy does not match, but pod already has it as matched
806				deletedPolicies = append(deletedPolicies, pol)
807			}
808		}
809	
810		return &policiesDiffRes{
811			addedPolicies:      addedPolicies,
812			deletedPolicies:    deletedPolicies,
813			newMatchedPolicies: newMatchedPolicies,
814		}
815	}
816	
817	// applyPodPolicyDiff applies the changes of the policies that match a pod to the state by updating:
818	// - the policy maps
819	//   - adding cgroup ids for policies that match now, but did not match before
820	//   - removing cgroup ids for policies that did not match, but did match before
821	//
822	// - pod.matchedPolicies with a slice of the new policy ids
823	func (m *state) applyPodPolicyDiff(pod *podInfo, polDiff *policiesDiffRes) {
824		// no changes, just return
825		if len(polDiff.addedPolicies) == 0 && len(polDiff.deletedPolicies) == 0 {
826			return
827		}
828	
829		var cgroupIDs []CgroupID
830		for _, addPol := range polDiff.addedPolicies {
831			cgroupIDs = addPol.matchingContainersCgroupIDs(pod.containers)
832			if err := addPol.polMap.addCgroupIDs(cgroupIDs); err != nil {
833				m.log.Warn("failed to update policy map",
834					logfields.Error, err,
835					"policy-id", addPol.id,
836					"pod-id", pod.id,
837					"cgroup-ids", cgroupIDs,
838					"reason", "labels change caused policy to match")
839			} else {
840				// update cgroup map if addCgroupIDs succeeds
841				if err := addPol.polMap.addPolicyIDs(addPol.id, cgroupIDs); err != nil {
842					m.log.Warn("failed to update cgroup map",
843						logfields.Error, err,
844						"policy-id", addPol.id,
845						"pod-id", pod.id,
846						"cgroup-ids", cgroupIDs,
847						"reason", "labels change caused policy to match")
848				}
849			}
850		}
851	
852		for _, delPol := range polDiff.deletedPolicies {
853			cgroupIDs = delPol.matchingContainersCgroupIDs(pod.containers)
854			if err := delPol.polMap.delCgroupIDs(delPol.id, cgroupIDs); err != nil {
855				m.log.Warn("failed to update policy map",
856					logfields.Error, err,
857					"policy-id", delPol.id,
858					"pod-id", pod.id,
859					"cgroup-ids", cgroupIDs,
860					"reason", "labels change caused policy to unmatch")
861			}
862		}
863		pod.matchedPolicies = polDiff.newMatchedPolicies
864	}
865	
866	func (pod *podInfo) containerDiff(newContainerIDs []string) ([]string, []string) {
867	
868		// maintain a hash of new ids. The values indicate whether the id was seen in existing ids
869		// or not
870		newIDs := make(map[string]bool)
871		for _, cid := range newContainerIDs {
872			newIDs[cid] = false
873		}
874	
875		addContIDs := []string{}
876		delContIDs := []string{}
877		for _, containerInfo := range pod.containers {
878			cid := containerInfo.id
879			if _, exists := newIDs[cid]; exists {
880				newIDs[cid] = true
881			} else {
882				delContIDs = append(delContIDs, cid)
883			}
884		}
885	
886		for cid, seen := range newIDs {
887			if !seen {
888				addContIDs = append(addContIDs, cid)
889			}
890		}
891	
892		return addContIDs, delContIDs
893	}
894	
895	// UpdatePod updates the pod state for a pod
896	// containerIDs contains all the running container ids for the given pod.
897	// This function will:
898	//   - check if pod labels changed. Add/delete policies if this is the case
899	//   - remove the containers that are not part of the containerIDs list
900	//   - add the ones that do not exist in the current state
901	//
902	// It is intended to be used from k8s watchers (where no cgroup information is available)
903	func (m *state) UpdatePod(podID PodID, namespace, workload, kind string, podLabels labels.Labels,
904		containerIDs []string, containerInfo []podhelpers.ContainerInfo) error {
905		m.mu.Lock()
906		defer m.mu.Unlock()
907	
908		dlog := m.DebugLogWithCallers(4).With(
909			"pod-id", podID,
910			"namespace", namespace,
911			"container-ids", containerIDs,
912			"container-info", containerInfo,
913		)
914	
915		pod := m.findPod(podID)
916		if pod == nil {
917			pod = m.addNewPod(podID, namespace, workload, kind, podLabels)
918			dlog.Info("UpdatePod: added pod")
919		} else if pod.namespace != namespace {
920			// sanity check: old and new namespace should match
921			return &podNamespaceConflictError{podID: podID, oldNs: pod.namespace, newNs: namespace}
922		}
923	
924		// labels changed: check if there are policies ads that:
925		// - did not match before, but they match now (addPols)
926		// - did match before, but they do not match now (delPols))
927		// and update state accordingly
928		if pod.labels.Cmp(podLabels) {
929			polDiff := m.policiesDiff(pod, podLabels)
930			m.DebugLogWithCallers(1).Info("UpdatePod: pod labels changed",
931				"pod-id", pod.id,
932				"pod-old-labels", pod.labels,
933				"pod-new-labels", podLabels,
934				"policy-diff", fmt.Sprintf("%+v", polDiff))
935			m.applyPodPolicyDiff(pod, polDiff)
936			pod.labels = podLabels
937		}
938	
939		// containers changed: check if there are new or deleted containers, and update the policy
940		// map
941		addIDs, delIDs := pod.containerDiff(containerIDs)
942		for _, cid := range delIDs {
943			containers := pod.delContainers(cid)
944			if len(containers) != 1 {
945				m.Debugf("UpdatePod: pod-id=%s container-id=%s had %d containers: %v", podID, cid, len(containers), containers)
946			}
947			m.delPodCgroupIDsFromPolicyMaps(pod, containers)
948		}
949	
950		// container names that are associated with addIDs
951		var addContainerInfo []podhelpers.ContainerInfo
952	
953		// find container names of the container IDs that should be added to pod
954		for addID := range addIDs {
955			for allID := range containerIDs {
956				if addIDs[addID] == containerIDs[allID] {
957					addContainerInfo = append(addContainerInfo, containerInfo[allID])
958				}
959			}
960		}
961	
962		m.addPodContainers(pod, addIDs, nil, addContainerInfo)
963		return nil
964	}
965	
966	func (m *state) GetNsId(stateID StateID) (*NSID, bool) {
967		if ns, ok := m.nsMap.nsIdMap.Get(stateID); ok {
968			return &ns, ok
969		}
970		return nil, false
971	}
972	
973	func (m *state) GetIdNs(id NSID) (StateID, bool) {
974		if stateID, ok := m.nsMap.nsNameMap.Get(id); ok {
975			return stateID, ok
976		}
977		return StateID(0), false
978	}
979	

