func TestK8sWatcher_GetPodInfo(t *testing.T) {
	controller := true
	var pods []interface{}
	pod := &v1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:              "test-pod",
			Namespace:         "kube-system",
			UID:               "1",
